// 取得輸入資料
const items = $input.all();

// 處理每個輸入項目
const output = items.map(item => {
  const fanSpeedArray = item.json.fan_speed;
  const edgeIdArray = item.json.edge_id;    // 取得 edge_id 陣列
  const roomIdArray = item.json.room_id;    // 取得 room_id 陣列

  // 將字串陣列轉換為數字並加總
  const sum = fanSpeedArray.reduce((total, speed) => {
    return total + Number(speed);
  }, 0);

  // 字串連接（不轉換為數字，直接連接）
  const stringConcat = fanSpeedArray.join('');

  return {
    json: {
      fan_speed_array: fanSpeedArray,       // 保留原始陣列
      fan_speed_sum: sum,                   // 加總結果
      fan_speed_count: fanSpeedArray.length, // 項目數量
      fan_speed_string: stringConcat,       // 字串連接結果
      edge_id: edgeIdArray,                 // edge_id 陣列
      room_id: roomIdArray                  // 新增 room_id 陣列
    }
  };
});

return output;

